// ═══════════════════════════════════════════════════════
// Step 13: Final Report Output
// Erzeugt den vollstaendigen Report als Markdown
// mit Tabelle und Zusammenfassung
// ═══════════════════════════════════════════════════════
const data = $input.item.json;
const config = data.config;
const reportTable = data.reportTable || [];
const summary = data.summary || {};

// --- Markdown Report Table ---
const tableHeader = `| Nr | Kategorie | Aspekt | ${config.ownCompanyShort} | ${config.competitorShort} (RAG) | ${config.competitorShort} (Benchmark) | Bewertung |`;
const tableSeparator = '|-----|-----------|--------|' + '-'.repeat(config.ownCompanyShort.length + 2) + '|' + '-'.repeat(config.competitorShort.length + 8) + '|' + '-'.repeat(config.competitorShort.length + 14) + '|-----------|';
const tableRows = reportTable.map(r =>
  `| ${r.Nr} | ${r.Kategorie} | ${r.Aspekt} | ${r[config.ownCompanyShort] || ''} | ${r[config.competitorShort + ' (RAG)'] || ''} | ${r[config.competitorShort + ' (Benchmark)'] || ''} | ${r.Bewertung} |`
).join('\n');

const summaryBlock = `## Zusammenfassung\n\n` +
  `| Metrik | Wert |\n` +
  `|--------|------|\n` +
  `| Verglichene Fakten | ${summary.totalFacts} |\n` +
  `| ${config.ownCompanyShort} besser | ${summary.ownBetter} |\n` +
  `| ${config.competitorShort} besser | ${summary.competitorBetter} |\n` +
  `| Gleichwertig | ${summary.equal} |\n` +
  `| Nicht eindeutig | ${summary.unclear} |\n`;

const fullReport = `# AVB-Vergleich: ${config.ownCompanyName} vs. ${config.competitorName}\n\n` +
  `**Erstellt:** ${data.meta.timestamp}\n` +
  `**Modell:** ${data.meta.model}\n` +
  `**Verglichene Fakten:** ${summary.totalFacts}\n` +
  `**Gesamt-Tokens Synthese:** ${data.meta.usage.totalTokens}\n` +
  `**Mitbewerber-Datenquelle:** RAG Collection ${config.competitorRagCollection}\n\n` +
  '---\n\n' +
  summaryBlock + '\n\n' +
  '---\n\n' +
  '# Executive Summary und Gegenueberstellung\n\n' +
  data.gesamtvergleich + '\n\n' +
  '---\n\n' +
  '# Vergleichstabelle\n\n' +
  tableHeader + '\n' + tableSeparator + '\n' + tableRows + '\n';

// Return both the structured table (for n8n table view) and the full report
return {
  report: fullReport,
  reportTable: reportTable,
  summary: summary,
  gesamtvergleich: data.gesamtvergleich,
  meta: data.meta
};
